define <8 x float> @widen_extract4(<8 x float> %ins, <2 x float> %ext) {
  %e1 = extractelement <2 x float> %ext, i32 0
  %i1 = insertelement <8 x float> %ins, float %e1, i32 2
  ret <8 x float> %i1
}

